module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const color = args.color || 'var(--accent-color)';
const sizes = { sm: '0.9em', md: '1em', lg: '1.15em' };
const size = sizes[String(args.size || 'md').toLowerCase()] || '1em';
const numbered = String(args.numbered) === 'true';
const hlast = String(args.hlast) === 'true';
const steps = sections.map((s) => (s || '').trim()).filter(Boolean);
const cls = 'mdp-mod-derivation' + (numbered ? ' mdp-dv-numbered' : '') + (hlast ? ' mdp-dv-hlast' : '');
let html = `\n\n<div class="${cls}" style="--dv-color:${color}; font-size:${size};">`;
steps.forEach((st) => {
  const idx = st.lastIndexOf('|');
  const expr = (idx >= 0 ? st.slice(0, idx) : st).trim();
  const reason = idx >= 0 ? st.slice(idx + 1).trim() : '';
  html += `<div class="mdp-dv-row"><div class="mdp-dv-expr">\n\n${expr}\n\n</div><div class="mdp-dv-reason">${reason ? esc(reason) : ''}</div></div>`;
});
html += `</div>\n\n`;
return html;
